/// Run all 4 models and report cosine deltas without asserting.
/// Useful for diagnostic comparison before Phase 2 gating.
#[test]
#[ignore = "requires all 4 model downloads"]
fn test_all_models_fixture_comparison_report() {
    let models = [
        (ModelId::BgeBase, "bge-base"),
        (ModelId::MiniLM, "minilm"),
        (ModelId::GteBase, "gte-base"),
        (ModelId::Nomic, "nomic"),
    ];

    let mut all_pass = true;
    let mut results = Vec::new();

    for (model_id, name) in &models {
        let (min_cos, avg_cos) = compare_model(*model_id, name);
        let pass = min_cos >= COSINE_THRESHOLD;
        if !pass {
            all_pass = false;
        }
        results.push((name, min_cos, avg_cos, pass));
    }

    println!("\n=== SUMMARY ===");
    println!("{:<12} {:>12} {:>12} {:>6}", "model", "min_cosine", "avg_cosine", "pass");
    for (name, min_cos, avg_cos, pass) in &results {
        println!(
            "{:<12} {:>12.6} {:>12.6} {:>6}",
            name,
            min_cos,
            avg_cos,
            if *pass { "YES" } else { "NO" }
        );
    }
    println!("threshold: {}", COSINE_THRESHOLD);

    assert!(
        all_pass,
        "One or more models failed cosine threshold — Phase 2 is blocked until fixed."
    );
}

